import{_ as n,o as i,c as t,ag as a}from"./chunks/framework.DXGyWiRo.js";const r="/images/lekt1102.jpg",s="/images/lekt1101.jpg",p="/images/lekt1103.jpg",g=JSON.parse('{"title":"Lektion 11","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion11.md","filePath":"lektionen/lektion11.md"}'),u={name:"lektionen/lektion11.md"};function o(d,e,l,h,m,c){return i(),t("div",null,[...e[0]||(e[0]=[a('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-11" tabindex="-1">Lektion 11 <a class="header-anchor" href="#lektion-11" aria-label="Permalink to &quot;Lektion 11&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>11.1. Doppelter Akkusativ</li><li>11.2. Wortliste</li><li>11.3. Übung</li><li>11.4. Wiederholungsübung</li></ul><h2 id="_11-1-doppelter-akkusativ" tabindex="-1">11.1. Doppelter Akkusativ <a class="header-anchor" href="#_11-1-doppelter-akkusativ" aria-label="Permalink to &quot;11.1. Doppelter Akkusativ&quot;">​</a></h2><p>Einige Verben können einen doppelten Akkusativ (dvitīyā) regieren:</p><p>Akkusativ der Person und Akkusativ der Sache</p><p>Hierzu gehören:</p><ul><li><p>Verben des Sprechens: spreche zu jemandem (Akkusativ) über etwas (Akkusativ); jemandem (Akkusativ) etwas (Akkusativ) sagen</p></li><li><p>Verben des Fragens: jemanden (Akkusativ) nach etwas (Akkusativ) fragen</p></li><li><p>Verben des Lehrens: jemanden (Akkusativ) etwas (Akkusativ) lehren</p></li><li><p>einige weitere Verben, bei denen es in den Wortlisten vermerkt wird</p></li></ul><p>Wird eine solche Konstruktion ins Passiv gesetzt, wird die Person (die gefragt wird usw.) in den Nominativ (prathamā) gesetzt, die Sache (nach der gefragt wird usw.) bleibt im Akkusativ.</p><p>z.B.</p><p>rāmo brāhmaṇaṃ dharmaṃ pṛcchati =  रामो ब्राह्मणं धर्मं पृच्छति = &quot;Rāma fragt den Brahmanen nach dem Dharma.&quot;</p><p>» Passiv: rāmeṇa brāhmaṇo dharmaṃ pṛcchyate = रामेण ब्राह्मणो धर्मं पृच्छ्यते = &quot;Rāma fragt den Brahmanen nach dem Dharma.&quot;</p><p>Diese Regel gilt nur, wenn sowohl als auch eine Sache Objekt sind. Ist eine Sache das einzige Objekt, steht diese nach dem Grundschema des Passivsatzes im Nominativ (prathamā):</p><p>z.B.</p><p>rāmo dharmaṃ pṛcchati = रामो धर्मं पृच्छति = &quot;Rāma fragt nach dem Dharma.&quot;</p><p>» Passiv: rāmeṇa dharmaḥ pṛcchyate =  रामेण धर्मः पृच्छ्यते = &quot;Rāma fragt nach dem Dharma.&quot;</p><h2 id="_11-2-wortliste" tabindex="-1">11.2. Wortliste <a class="header-anchor" href="#_11-2-wortliste" aria-label="Permalink to &quot;11.2. Wortliste&quot;">​</a></h2><p>iti इति : so</p><p>(steht nach der Formulierung eines Gedankens, Wunsches, Ausspruchs. Zitates gleichsam als Anführungszeichen (&quot;). z.B. साधवः स्वर्गं गच्छन्तीति ब्राह्मणा वदन्ति &quot;Brahmanen sagen: &quot;Heilige kommen in den Himmel&quot;&quot; = &quot;Brahmanen sagen, dass Heilige in den Himmel kommen&quot;. Für die Übersetzung ist zu beachten, dass es im Sanskrit keine indirekte Rede gibt, dass darum Bildungen mit iti im Deutschen oft in indirekter Rede wiedergegeben werden müssen (alles andere ist schlechte Übersetzung!).</p><p>... (Zitat) ... इति श्रुतिः = &quot;so der Veda&quot;</p><p>Oft ist nach iti ein Verb des Denkens hinzuzudenken: ... iti tut er das und das = &quot;denkend: &quot;...&quot; tut er das und das&quot; &quot;weil ... tut er das und das&quot;. Dies ist eine Möglichkeit Motive für Handlungen auszudrücken. Im Deutschen müssen solche Ausdrücke in idiomatischem deutsch wiedergegeben werden und nicht in sanskritischem Deutsch (Übersetzungen wie &quot;Denkend: &quot;ich habe Hunger&quot; geht er ins Restaurant&quot; sind falsch, richtig: &quot;Weil er Hunger hat, geht er ins Restaurant&quot;.)</p><p>evam एवम् : so (adverbiell, z.B. एवं जयति &quot;so siegt er&quot;. Beachten Sie den Unterschied im Gebrauch von iti und evam!)</p><p>na न : nicht</p><p>(verneint einzelne Worte oder auch ganze Sätze. Beim Verneinen einzelner Worte steht na unmittelbar vor dem verneinten Wort: न साधुः &quot;ein nicht guter&quot;. Wird ein satz verneint, steht na entweder zu Beginn des Satzes -- so, wenn man einen Gegensatz betonen will und bei betonten Verneinungen -- oder unmittelbar vor dem Verb.)</p><p>putra m. पुत्र : Sohn</p><p>(In Indien war es notwendig einen Sohn zu zeugen, der die Opfer für die Vorfahren darbringen konnte.)</p><p>dharma m. धर्म : (&quot;das, was fest ist&quot; d.h.) Recht, Gesetz, Sitte, Charakter</p><p>(entspricht am ehesten dem mittelalterlichen lex naturae = Naturgesetz, Sittengesetz und rechte Sozialordnung. dharma ist für Hindus nicht für alle gleich, sondern jeder hat nach varṇa und āśrama (Lebensstadium, dazu Basham, Wonder S. 159f.) seine je eigenen Pflichten: svadharma)</p><p>Gegensatz zu dharma:</p><p>adharma m. अधर्म : Unrecht</p><p>iṣ 6 P (icchati) इष् इच्छति : wünschen (iṣ-ccha-ti) (wird von den einheimischen Grammatikern zur 6. Präsensklasse gerechnet, obwohl es eine Bildung mit einem Präsensstammsuffix -ccha- ist wie gam ga-ccha-ti</p><p>Einige Nominalbildungen:</p><p>vad 1 P वद् : sagen</p><blockquote><p>vāda m. वाद : Ausspruch, Aussage, Wort</p><p>vadana n. वदन : das Sprechen ; Sprechwerkzeug: Mund, Gesicht</p><p><img src="'+r+'" alt=""><br> Abb.: वदनानि, Jamalpur district (জামালপুর জেলা), Bangladesh (বাংলাদেশ) <br> [Bildquelle: Juan Blazquez. -- <a href="http://www.flickr.com/photos/juanblazquez/261690111/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/juanblazquez/261690111/</a>. -- Zugriff am 2008-11-28. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p></blockquote><p>prach 6 P प्रछ् : fragen</p><blockquote><p>praśna m. प्रश्न : Frage (Suffix -na wie in yaj-na)</p></blockquote><p>iṣ 6 P इष् : wünschen</p><blockquote><p>iṣṭi f. इष्टि : Wunsch (iṣ + -ti)</p></blockquote><h2 id="_11-3-ubung" tabindex="-1">11.3. Übung <a class="header-anchor" href="#_11-3-ubung" aria-label="Permalink to &quot;11.3. Übung&quot;">​</a></h2><p>A) Übersetzen Sie untenstehende Sätze</p><p>१. ऋषिः सत्यं वदति ।</p><p>२. ब्राह्मणः पुत्रमिच्छति ।</p><p>३. साधुः स्वर्गं गच्छति ।</p><p>४. ब्राह्मणो ऽनृतं न वदतीति स्मृतिः ।</p><p>५. क्षत्रियो ब्राह्मणं धर्मं पृच्छति ।</p><p>६. एवं ब्राह्मणो यज्ञेन देवं यजति ।</p><p>७. पुत्रः पापं करोतीति वैश्या मन्यते ।</p><p>८. क्षत्रियः क्षत्रियेण सह युध्यते</p><p>९. अधर्मो ऽनृतमिति पुत्रः पापं न करोति ।</p><p>१०. अयं क्षत्रियो धर्मं रक्षति ।</p><p>११. को ऽग्निं यजते ।</p><p>१२. स श्रावको बुद्धं धर्मं पृच्छति ॥</p><p>B) Setzen Sie die Sätze von A) in Passivkonstruktion</p><p>C) Setzen Sie in den Sätzen A), wo es sinnvoll ist, Subjekt, Objekt und Prädikat in den Plural</p><p>D) Bilden Sie zu den nach C) gebildeten Sätzen die Passivkonstruktion</p><p><img src="'+s+'" alt=""><br> Abb.: श्रावको महाकाश्यपः<br> War unter Buddha Guatamas Jüngern der Spezialist für Vinaya (Ordensdisziplin)<br> [Bildquelle: Wikipedia, Public domain]</p><h2 id="_11-4-wiederholungsubung" tabindex="-1">11.4. Wiederholungsübung <a class="header-anchor" href="#_11-4-wiederholungsubung" aria-label="Permalink to &quot;11.4. Wiederholungsübung&quot;">​</a></h2><p>A) Übersetzen Sie ins Sanskrit mit Passivkonstruktionen:</p><p>1. Vaiśyafrauen fragen Brahmanen nach dem Dharma.</p><p>2. Der Lehrer spricht ein Mantra.</p><p>3. Heilige Frauen gelangen in einen Himmel.</p><p>4. Ein vedischer Weiser tut nichts Böses.</p><p>5. Brahmanen verehren als Opferpriester die Göttin mit Opfern.</p><p>6. Die Śūdrafrau geht ins Dorf.</p><p>7. Wer sieht die  Wahrheit?</p><p>B)</p><p>1. Geben Sie mit einem Dvandva die Aufgaben aller Zweimalgeborenen an. Lösen Sie das Kompositum in Sanskrit auf.</p><p>2. Geben Sie mit einem Dvandva die Aufgaben der Vaiśyas an. Lösen Sie das Kompositum in Sanskrit auf.</p><p>C) Übersetzen Sie:</p><p>१. श्रवणेन श्रूयते ।</p><p>२. कर्षकैः कृष्यते ।</p><p>३. श्रावकेणेश्वरो नेज्यते ।</p><p>४. रक्षिक्या गुरू रक्ष्यते ।</p><p>५. ब्राह्मणेनानृतं नोद्यते ।</p><p>६. शूद्रेतरा ।</p><p>७. शिक्षा कल्पो व्याकरणं निरुक्तं छन्दो ज्योतिषमङ्गानि ।</p><p>८. आन्वीक्षिकीत्रयीवार्त्तादण्डनीतयो विद्याः ॥</p><p>D) Übersetzen Sie und setzen Sie in Sanskrit Agens, Objekt und Verb in den Plural:</p><p>१. फलमश्नुते ।</p><p>२. गुरुणा सत्यमुद्यते ।</p><p>३. वैश्यः पशुं लभते ।</p><p>४. पुत्रः पुण्यं करोति ॥</p><p>E) Verwandeln Sie die Sätze C)1-5 in Aktivkonstruktionen.</p><p><img src="'+p+'" alt=""><br> Abb.: कर्षकेण कृष्यते<br> [Bildquelle: Ray Witlin / World Bank. -- <a href="http://www.flickr.com/photos/worldbank/2183019617/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/worldbank/2183019617/</a>. -- Zugriff am 2008-11-18. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p>',85)])])}const b=n(u,[["render",o]]);export{g as __pageData,b as default};
